  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import {
  4	  Toolbar,
  5	  ToolbarGroup,
  6	  ToolbarItem,
  7	  Card,
  8	  CardBody,
  9	  EmptyState,
 10	  EmptyStateVariant,
 11	  EmptyStateHeader
 12	} from '@patternfly/react-core';
 13	import { kialiStyle } from 'styles/StyleUtils';
 14	import { router, HistoryManager, URLParam, location } from '../../app/History';
 15	import * as API from '../../services/Api';
 16	import { KialiAppState } from '../../store/Store';
 17	import { TimeRange, evalTimeRange, TimeInMilliseconds, isEqualTimeRange } from '../../types/Common';
 18	import * as AlertUtils from '../../utils/AlertUtils';
 19	import { RenderComponentScroll } from '../../components/Nav/Page';
 20	import * as MetricsHelper from './Helper';
 21	import { KioskElement } from '../Kiosk/KioskElement';
 22	import { MetricsSettings, LabelsSettings } from '../MetricsOptions/MetricsSettings';
 23	import { MetricsSettingsDropdown } from '../MetricsOptions/MetricsSettingsDropdown';
 24	import { MetricsRawAggregation } from '../MetricsOptions/MetricsRawAggregation';
 25	import { TimeDurationModal } from '../Time/TimeDurationModal';
 26	import { GrafanaLinks } from './GrafanaLinks';
 27	import { MetricsObjectTypes } from 'types/Metrics';
 28	import { SpanOverlay, JaegerLineInfo } from './SpanOverlay';
 29	import { DashboardModel } from 'types/Dashboards';
 30	import { Overlay } from 'types/Overlay';
 31	import { Aggregator, DashboardQuery } from 'types/MetricsOptions';
 32	import { RawOrBucket } from 'types/VictoryChartInfo';
 33	import { Dashboard } from 'components/Charts/Dashboard';
 34	import { KialiDispatch } from 'types/Redux';
 35	import { bindActionCreators } from 'redux';
 36	import { UserSettingsActions } from '../../actions/UserSettingsActions';
 37	import { timeRangeSelector } from '../../store/Selectors';
 38	import { TimeDurationIndicator } from '../Time/TimeDurationIndicator';
 39	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 40	import { TraceSpansLimit } from './TraceSpansLimit';
 41	import { GrafanaInfo } from '../../types/GrafanaInfo';
 42	
 43	type MetricsState = {
 44	  cluster?: string;
 45	  dashboard?: DashboardModel;
 46	  grafanaInfo: GrafanaInfo;
 47	  isTimeOptionsOpen: boolean;
 48	  labelsSettings: LabelsSettings;
 49	  showSpans: boolean;
 50	  spanOverlay?: Overlay<JaegerLineInfo>;
 51	  tabHeight: number;
 52	  traceLimit: number;
 53	};
 54	
 55	type CustomMetricsProps = {
 56	  app: string;
 57	  appLabelName?: string;
 58	  embedded?: boolean;
 59	  height?: number;
 60	  lastRefreshAt: TimeInMilliseconds;
 61	  namespace: string;
 62	  template: string;
 63	  version?: string;
 64	  versionLabelName?: string;
 65	  workload?: string;
 66	  workloadType?: string;
 67	};
 68	
 69	type ReduxStateProps = {
 70	  kiosk: string;
 71	  timeRange: TimeRange;
 72	  tracingIntegration: boolean;
 73	};
 74	
 75	type ReduxDispatchProps = {
 76	  setTimeRange: (range: TimeRange) => void;
 77	};
 78	
 79	type Props = ReduxStateProps & ReduxDispatchProps & CustomMetricsProps;
 80	
 81	// lower that the standard default, we apply it to several small charts
 82	const traceLimitDefault = 20;
 83	
 84	const fullHeightStyle = kialiStyle({
 85	  height: '100%'
 86	});
 87	
 88	const emptyStyle = kialiStyle({
 89	  display: 'flex',
 90	  justifyContent: 'center',
 91	  alignItems: 'center',
 92	  overflow: 'hidden',
 93	  // fix height + padding
 94	  height: '350px',
 95	  textAlign: 'center'
 96	});
 97	
 98	class CustomMetricsComponent extends React.Component<Props, MetricsState> {
 99	  toolbarRef: React.RefObject<HTMLDivElement>;
100	  options: DashboardQuery;
101	  spanOverlay: SpanOverlay;
102	
103	  constructor(props: Props) {
104	    super(props);
105	    this.toolbarRef = React.createRef<HTMLDivElement>();
106	    const settings = MetricsHelper.retrieveMetricsSettings(traceLimitDefault);
107	    this.options = this.initOptions(settings);
108	
109	    // Initialize active filters from URL
110	    const cluster = HistoryManager.getClusterName();
111	    this.state = {
112	      cluster: cluster,
113	      grafanaInfo: {
114	        externalLinks: []
115	      },
116	      isTimeOptionsOpen: false,
117	      labelsSettings: settings.labelsSettings,
118	      showSpans: settings.showSpans,
119	      tabHeight: 300,
120	      traceLimit: settings.spanLimit
121	    };
122	
123	    this.spanOverlay = new SpanOverlay(changed => this.setState({ spanOverlay: changed }));
124	  }
125	
126	  private initOptions = (settings: MetricsSettings): DashboardQuery => {
127	    const filters = this.props.app && this.props.appLabelName ? `${this.props.appLabelName}:${this.props.app}` : '';
128	
129	    const options: DashboardQuery = this.props.version
130	      ? {
131	          labelsFilters: `${filters},${this.props.versionLabelName}:${this.props.version}`
132	        }
133	      : {
134	          labelsFilters: filters,
135	          additionalLabels: 'version:Version'
136	        };
137	
138	    MetricsHelper.settingsToOptions(settings, options, []);
139	
140	    return options;
141	  };
142	
143	  componentDidMount(): void {
144	    this.refresh();
145	  }
146	
147	  componentDidUpdate(prevProps: Props, prevState: MetricsState): void {
148	    if (
149	      this.props.namespace !== prevProps.namespace ||
150	      this.props.app !== prevProps.app ||
151	      this.props.workload !== prevProps.workload ||
152	      this.props.version !== prevProps.version ||
153	      this.props.template !== prevProps.template ||
154	      this.props.lastRefreshAt !== prevProps.lastRefreshAt ||
155	      this.state.showSpans !== prevState.showSpans ||
156	      this.state.traceLimit !== prevState.traceLimit ||
157	      !isEqualTimeRange(this.props.timeRange, prevProps.timeRange)
158	    ) {
159	      const settings = MetricsHelper.retrieveMetricsSettings(this.state.traceLimit);
160	      this.options = this.initOptions(settings);
161	      this.spanOverlay.reset();
162	      this.refresh();
163	    }
164	  }
165	
166	  private refresh = (): void => {
167	    this.fetchMetrics();
168	
169	    if (this.state.showSpans) {
170	      this.spanOverlay.fetch({
171	        cluster: this.state.cluster,
172	        limit: this.state.traceLimit,
173	        namespace: this.props.namespace,
174	        range: this.props.timeRange,
175	        target: this.props.workload || this.props.app,
176	        targetKind: this.props.workload ? MetricsObjectTypes.WORKLOAD : MetricsObjectTypes.APP
177	      });
178	    }
179	  };
180	
181	  private fetchMetrics = (): void => {
182	    // Time range needs to be reevaluated everytime fetching
183	    MetricsHelper.timeRangeToOptions(this.props.timeRange, this.options);
184	
185	    // Workload name can be used to find personalized dashboards defined at workload level
186	    this.options.workload = this.props.workload;
187	    this.options.workloadType = this.props.workloadType;
188	
189	    API.getCustomDashboard(this.props.namespace, this.props.template, this.options, this.state.cluster)
190	      .then(response => {
191	        const labelsSettings = MetricsHelper.extractLabelsSettings(response.data, this.state.labelsSettings);
192	
193	        this.setState({
194	          dashboard: response.data,
195	          labelsSettings: labelsSettings,
196	          grafanaInfo: response.data
197	        });
198	      })
199	      .catch(error => {
200	        AlertUtils.addError('Could not fetch custom dashboard.', error);
201	      });
202	  };
203	
204	  private onMetricsSettingsChanged = (settings: MetricsSettings): void => {
205	    MetricsHelper.settingsToOptions(settings, this.options, []);
206	    this.fetchMetrics();
207	  };
208	
209	  private onLabelsFiltersChanged = (labelsFilters: LabelsSettings): void => {
210	    this.setState({ labelsSettings: labelsFilters });
211	  };
212	
213	  private onRawAggregationChanged = (aggregator: Aggregator): void => {
214	    this.options.rawDataAggregator = aggregator;
215	    this.fetchMetrics();
216	  };
217	
218	  private onClickDataPoint = (_, datum: RawOrBucket<JaegerLineInfo>): void => {
219	    if ('start' in datum && 'end' in datum) {
220	      // Zoom-in bucket
221	      this.onDomainChange([datum.start as Date, datum.end as Date]);
222	    } else if ('traceId' in datum) {
223	      const traceId = datum.traceId;
224	      const spanId = datum.spanId;
225	
226	      const traceUrl = `/namespaces/${this.props.namespace}/applications/${this.props.app}?tab=traces&${URLParam.TRACING_TRACE_ID}=${traceId}&${URLParam.TRACING_SPAN_ID}=${spanId}`;
227	
228	      if (isParentKiosk(this.props.kiosk)) {
229	        kioskContextMenuAction(traceUrl);
230	      } else {
231	        router.navigate(traceUrl);
232	      }
233	    }
234	  };
235	
236	  private onDomainChange = (dates: [Date, Date]): void => {
237	    if (dates && dates[0] && dates[1]) {
238	      const range: TimeRange = {
239	        from: dates[0].getTime(),
240	        to: dates[1].getTime()
241	      };
242	
243	      this.props.setTimeRange(range);
244	    }
245	  };
246	
247	  renderFetchMetrics = (title: string): React.ReactNode => {
248	    return (
249	      <div className={emptyStyle}>
250	        <EmptyState variant={EmptyStateVariant.sm}>
251	          <EmptyStateHeader titleText={<>{title}</>} headingLevel="h5" />
252	        </EmptyState>
253	      </div>
254	    );
255	  };
256	
257	  render(): React.ReactNode {
258	    const urlParams = new URLSearchParams(location.getSearch());
259	    const expandedChart = urlParams.get('expand') || undefined;
260	
261	    // 20px (card margin) + 24px (card padding) + 51px (toolbar) + 15px (toolbar padding) + 24px (card padding) + 20px (card margin)
262	    const toolbarHeight = this.toolbarRef.current ? this.toolbarRef.current.clientHeight : 51;
263	    const toolbarSpace = 20 + 24 + toolbarHeight + 15 + 24 + 20;
264	    const dashboardHeight = (this.props.height ? this.props.height : this.state.tabHeight) - toolbarSpace;
265	
266	    const dashboard = this.state.dashboard && (
267	      <Dashboard
268	        dashboard={this.state.dashboard}
269	        customMetric={true}
270	        template={this.props.template}
271	        labelValues={MetricsHelper.convertAsPromLabels(this.state.labelsSettings)}
272	        maximizedChart={expandedChart}
273	        expandHandler={this.expandHandler}
274	        onClick={this.onClickDataPoint}
275	        showSpans={this.state.showSpans}
276	        dashboardHeight={dashboardHeight}
277	        overlay={this.state.spanOverlay}
278	        timeWindow={evalTimeRange(this.props.timeRange)}
279	        brushHandlers={{ onDomainChangeEnd: (_, props) => this.onDomainChange(props.currentDomain.x) }}
280	      />
281	    );
282	
283	    const content = (
284	      <>
285	        {this.renderOptionsBar()}
286	        {this.state.dashboard !== undefined ? dashboard : this.renderFetchMetrics('Loading metrics')}
287	      </>
288	    );
289	
290	    return (
291	      <>
292	        {this.props.embedded ? (
293	          <>{content}</>
294	        ) : (
295	          <RenderComponentScroll onResize={height => this.setState({ tabHeight: height })}>
296	            <Card className={fullHeightStyle}>
297	              <CardBody>{content}</CardBody>
298	            </Card>
299	          </RenderComponentScroll>
300	        )}
301	
302	        <TimeDurationModal
303	          customDuration={true}
304	          isOpen={this.state.isTimeOptionsOpen}
305	          onConfirm={this.toggleTimeOptionsVisibility}
306	          onCancel={this.toggleTimeOptionsVisibility}
307	        />
308	      </>
309	    );
310	  }
311	
312	  private onTraceSpansChange = (checked: boolean, limit: number): void => {
313	    const urlParams = new URLSearchParams(location.getSearch());
314	    urlParams.set(URLParam.SHOW_SPANS, String(checked));
315	    if (checked) {
316	      urlParams.set(URLParam.TRACING_LIMIT_TRACES, String(limit));
317	    } else {
318	      urlParams.delete(URLParam.SHOW_SPANS);
319	    }
320	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
321	    this.setState({ showSpans: checked, traceLimit: limit });
322	  };
323	
324	  private renderOptionsBar = (): React.ReactNode => {
325	    const hasHistograms =
326	      this.state.dashboard !== undefined && this.state.dashboard.charts.some(chart => chart.metrics.some(m => m.stat));
327	
328	    const hasLabels = this.state.labelsSettings.size > 0;
329	
330	    return (
331	      <div ref={this.toolbarRef}>
332	        <Toolbar style={{ paddingBottom: 15 }}>
333	          <ToolbarGroup>
334	            {(hasHistograms || hasLabels) && (
335	              <ToolbarItem>
336	                <MetricsSettingsDropdown
337	                  onChanged={this.onMetricsSettingsChanged}
338	                  onLabelsFiltersChanged={this.onLabelsFiltersChanged}
339	                  direction={this.state.dashboard?.title || 'dashboard'}
340	                  labelsSettings={this.state.labelsSettings}
341	                  hasHistograms={hasHistograms}
342	                  hasHistogramsAverage={hasHistograms}
343	                  hasHistogramsPercentiles={hasHistograms}
344	                />
345	              </ToolbarItem>
346	            )}
347	
348	            <ToolbarItem>
349	              <MetricsRawAggregation onChanged={this.onRawAggregationChanged} />
350	            </ToolbarItem>
351	
352	            {this.props.tracingIntegration && (
353	              <ToolbarItem style={{ alignSelf: 'center' }}>
354	                <TraceSpansLimit
355	                  label="Spans"
356	                  onChange={this.onTraceSpansChange}
357	                  showSpans={this.state.showSpans}
358	                  traceLimit={this.state.traceLimit}
359	                />
360	              </ToolbarItem>
361	            )}
362	
363	            <KioskElement>
364	              <ToolbarItem style={{ marginLeft: 'auto' }}>
365	                <TimeDurationIndicator onClick={this.toggleTimeOptionsVisibility} />
366	              </ToolbarItem>
367	            </KioskElement>
368	          </ToolbarGroup>
369	
370	          <ToolbarGroup style={{ marginLeft: 'auto', paddingRight: '20px' }}>
371	            <GrafanaLinks
372	              links={this.state.grafanaInfo.externalLinks}
373	              namespace={this.props.namespace}
374	              object={this.props.workload ? this.props.workload : this.props.app}
375	              objectType={this.props.workload ? MetricsObjectTypes.WORKLOAD : MetricsObjectTypes.APP}
376	              datasourceUID={this.state.grafanaInfo.datasourceUID}
377	              version={this.props.version}
378	            />
379	          </ToolbarGroup>
380	        </Toolbar>
381	      </div>
382	    );
383	  };
384	
385	  private expandHandler = (expandedChart?: string): void => {
386	    const urlParams = new URLSearchParams(location.getSearch());
387	    urlParams.delete('expand');
388	
389	    if (expandedChart) {
390	      urlParams.set('expand', expandedChart);
391	    }
392	
393	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
394	  };
395	
396	  private toggleTimeOptionsVisibility = (): void => {
397	    this.setState(prevState => ({ isTimeOptionsOpen: !prevState.isTimeOptionsOpen }));
398	  };
399	}
400	
401	const mapStateToProps = (state: KialiAppState): ReduxStateProps => {
402	  return {
403	    kiosk: state.globalState.kiosk,
404	    timeRange: timeRangeSelector(state),
405	    tracingIntegration: state.tracingState.info ? state.tracingState.info.integration : false
406	  };
407	};
408	
409	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
410	  return {
411	    setTimeRange: bindActionCreators(UserSettingsActions.setTimeRange, dispatch)
412	  };
413	};
414	
415	export const CustomMetrics = connect(mapStateToProps, mapDispatchToProps)(CustomMetricsComponent);

