  5	  ToolbarGroup,
  6	  ToolbarItem,
  7	  Card,
  8	  CardBody,
  9	  EmptyState,
 10	  EmptyStateVariant
 11	} from '@patternfly/react-core';
 12	import { kialiStyle } from 'styles/StyleUtils';
 13	import { router, HistoryManager, URLParam, location } from '../../app/History';
 14	import * as API from '../../services/Api';
 15	import { KialiAppState } from '../../store/Store';
 16	import { TimeRange, evalTimeRange, TimeInMilliseconds, isEqualTimeRange } from '../../types/Common';
 17	import * as AlertUtils from '../../utils/AlertUtils';
 18	import { RenderComponentScroll } from '../../components/Nav/Page';
 19	import * as MetricsHelper from './Helper';
 20	import { KioskElement } from '../Kiosk/KioskElement';
 21	import { MetricsSettings, LabelsSettings } from '../MetricsOptions/MetricsSettings';
 22	import { MetricsSettingsDropdown } from '../MetricsOptions/MetricsSettingsDropdown';
 23	import { MetricsRawAggregation } from '../MetricsOptions/MetricsRawAggregation';
 24	import { TimeDurationModal } from '../Time/TimeDurationModal';
 25	import { GrafanaLinks } from './GrafanaLinks';
 26	import { MetricsObjectTypes } from 'types/Metrics';
 27	import { SpanOverlay, JaegerLineInfo } from './SpanOverlay';
 28	import { DashboardModel } from 'types/Dashboards';
 29	import { Overlay } from 'types/Overlay';
 30	import { Aggregator, DashboardQuery } from 'types/MetricsOptions';
 31	import { RawOrBucket } from 'types/VictoryChartInfo';
 32	import { Dashboard } from 'components/Charts/Dashboard';
 33	import { KialiDispatch } from 'types/Redux';
 34	import { bindActionCreators } from 'redux';
 35	import { UserSettingsActions } from '../../actions/UserSettingsActions';
 36	import { timeRangeSelector } from '../../store/Selectors';
 37	import { TimeDurationIndicator } from '../Time/TimeDurationIndicator';
 38	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 39	import { TraceSpansLimit } from './TraceSpansLimit';
 40	import { GrafanaInfo } from '../../types/GrafanaInfo';
 41	
 42	type MetricsState = {
 43	  cluster?: string;
 44	  dashboard?: DashboardModel;
 45	  grafanaInfo: GrafanaInfo;
 46	  isTimeOptionsOpen: boolean;
 47	  labelsSettings: LabelsSettings;
 48	  showSpans: boolean;
 49	  spanOverlay?: Overlay<JaegerLineInfo>;
 50	  tabHeight: number;
 51	  traceLimit: number;
 52	};
 53	
 54	type CustomMetricsProps = {
 55	  app: string;
 56	  appLabelName?: string;
 57	  embedded?: boolean;
 58	  height?: number;
 59	  lastRefreshAt: TimeInMilliseconds;
 60	  namespace: string;
 61	  template: string;
 62	  version?: string;
 63	  versionLabelName?: string;
 64	  workload?: string;
 65	  workloadType?: string;
 66	};
 67	
 68	type ReduxStateProps = {
 69	  kiosk: string;
 70	  timeRange: TimeRange;
 71	  tracingIntegration: boolean;
 72	};
 73	
 74	type ReduxDispatchProps = {
 75	  setTimeRange: (range: TimeRange) => void;
 76	};
 77	
 78	type Props = ReduxStateProps & ReduxDispatchProps & CustomMetricsProps;
 79	
 80	// lower that the standard default, we apply it to several small charts
 81	const traceLimitDefault = 20;
 82	
 83	const fullHeightStyle = kialiStyle({
 84	  height: '100%'
 85	});
 86	
 87	const emptyStyle = kialiStyle({
 88	  display: 'flex',
 89	  justifyContent: 'center',
 90	  alignItems: 'center',
 91	  overflow: 'hidden',
 92	  // fix height + padding
 93	  height: '350px',
 94	  textAlign: 'center'
 95	});
 96	
 97	class CustomMetricsComponent extends React.Component<Props, MetricsState> {
 98	  toolbarRef: React.RefObject<HTMLDivElement>;
 99	  options: DashboardQuery;
100	  spanOverlay: SpanOverlay;
101	
102	  constructor(props: Props) {
103	    super(props);
104	    this.toolbarRef = React.createRef<HTMLDivElement>();
105	    const settings = MetricsHelper.retrieveMetricsSettings(traceLimitDefault);
106	    this.options = this.initOptions(settings);
107	
108	    // Initialize active filters from URL
109	    const cluster = HistoryManager.getClusterName();
110	    this.state = {
111	      cluster: cluster,
112	      grafanaInfo: {
113	        externalLinks: []
114	      },
115	      isTimeOptionsOpen: false,
116	      labelsSettings: settings.labelsSettings,
117	      showSpans: settings.showSpans,
118	      tabHeight: 300,
119	      traceLimit: settings.spanLimit
120	    };
121	
122	    this.spanOverlay = new SpanOverlay(changed => this.setState({ spanOverlay: changed }));
123	  }
124	
125	  private initOptions = (settings: MetricsSettings): DashboardQuery => {
126	    const filters = this.props.app && this.props.appLabelName ? `${this.props.appLabelName}:${this.props.app}` : '';
127	
128	    const options: DashboardQuery = this.props.version
129	      ? {
130	          labelsFilters: `${filters},${this.props.versionLabelName}:${this.props.version}`
131	        }
132	      : {
133	          labelsFilters: filters,
134	          additionalLabels: 'version:Version'
135	        };
136	
137	    MetricsHelper.settingsToOptions(settings, options, []);
138	
139	    return options;
140	  };
141	
142	  componentDidMount(): void {
143	    this.refresh();
144	  }
145	
146	  componentDidUpdate(prevProps: Props, prevState: MetricsState): void {
147	    if (
148	      this.props.namespace !== prevProps.namespace ||
149	      this.props.app !== prevProps.app ||
150	      this.props.workload !== prevProps.workload ||
151	      this.props.version !== prevProps.version ||
152	      this.props.template !== prevProps.template ||
153	      this.props.lastRefreshAt !== prevProps.lastRefreshAt ||
154	      this.state.showSpans !== prevState.showSpans ||
155	      this.state.traceLimit !== prevState.traceLimit ||
156	      !isEqualTimeRange(this.props.timeRange, prevProps.timeRange)
157	    ) {
158	      const settings = MetricsHelper.retrieveMetricsSettings(this.state.traceLimit);
159	      this.options = this.initOptions(settings);
160	      this.spanOverlay.reset();
161	      this.refresh();
162	    }
163	  }
164	
165	  private refresh = (): void => {
166	    this.fetchMetrics();
167	
168	    if (this.state.showSpans) {
169	      this.spanOverlay.fetch({
170	        cluster: this.state.cluster,
171	        limit: this.state.traceLimit,
172	        namespace: this.props.namespace,
173	        range: this.props.timeRange,
174	        target: this.props.workload || this.props.app,
175	        targetKind: this.props.workload ? MetricsObjectTypes.WORKLOAD : MetricsObjectTypes.APP
176	      });
177	    }
178	  };
179	
180	  private fetchMetrics = (): void => {
181	    // Time range needs to be reevaluated everytime fetching
182	    MetricsHelper.timeRangeToOptions(this.props.timeRange, this.options);
183	
184	    // Workload name can be used to find personalized dashboards defined at workload level
185	    this.options.workload = this.props.workload;
186	    this.options.workloadType = this.props.workloadType;
187	
188	    API.getCustomDashboard(this.props.namespace, this.props.template, this.options, this.state.cluster)
189	      .then(response => {
190	        const labelsSettings = MetricsHelper.extractLabelsSettings(response.data, this.state.labelsSettings);
191	
192	        this.setState({
193	          dashboard: response.data,
194	          labelsSettings: labelsSettings,
195	          grafanaInfo: response.data
196	        });
197	      })
198	      .catch(error => {
199	        AlertUtils.addError('Could not fetch custom dashboard.', error);
200	      });
201	  };
202	
203	  private onMetricsSettingsChanged = (settings: MetricsSettings): void => {
204	    MetricsHelper.settingsToOptions(settings, this.options, []);
205	    this.fetchMetrics();
206	  };
207	
208	  private onLabelsFiltersChanged = (labelsFilters: LabelsSettings): void => {
209	    this.setState({ labelsSettings: labelsFilters });
210	  };
211	
212	  private onRawAggregationChanged = (aggregator: Aggregator): void => {
213	    this.options.rawDataAggregator = aggregator;
214	    this.fetchMetrics();
215	  };
216	
217	  private onClickDataPoint = (_, datum: RawOrBucket<JaegerLineInfo>): void => {
218	    if ('start' in datum && 'end' in datum) {
219	      // Zoom-in bucket
220	      this.onDomainChange([datum.start as Date, datum.end as Date]);
221	    } else if ('traceId' in datum) {
222	      const traceId = datum.traceId;
223	      const spanId = datum.spanId;
224	
225	      const traceUrl = `/namespaces/${this.props.namespace}/applications/${this.props.app}?tab=traces&${URLParam.TRACING_TRACE_ID}=${traceId}&${URLParam.TRACING_SPAN_ID}=${spanId}`;
226	
227	      if (isParentKiosk(this.props.kiosk)) {
228	        kioskContextMenuAction(traceUrl);
229	      } else {
230	        router.navigate(traceUrl);
231	      }
232	    }
233	  };
234	
235	  private onDomainChange = (dates: [Date, Date]): void => {
236	    if (dates && dates[0] && dates[1]) {
237	      const range: TimeRange = {
238	        from: dates[0].getTime(),
239	        to: dates[1].getTime()
240	      };
241	
242	      this.props.setTimeRange(range);
243	    }
244	  };
245	
246	  renderFetchMetrics = (title: string): React.ReactNode => {
247	    return (
248	      <div className={emptyStyle}>
249	        <EmptyState variant={EmptyStateVariant.sm} titleText={<>{title}</>} headingLevel="h5">
250	        </EmptyState>
251	      </div>
252	    );
253	  };
254	
255	  render(): React.ReactNode {
256	    const urlParams = new URLSearchParams(location.getSearch());
257	    const expandedChart = urlParams.get('expand') || undefined;
258	
259	    // 20px (card margin) + 24px (card padding) + 51px (toolbar) + 15px (toolbar padding) + 24px (card padding) + 20px (card margin)
260	    const toolbarHeight = this.toolbarRef.current ? this.toolbarRef.current.clientHeight : 51;
261	    const toolbarSpace = 20 + 24 + toolbarHeight + 15 + 24 + 20;
262	    const dashboardHeight = (this.props.height ? this.props.height : this.state.tabHeight) - toolbarSpace;
263	
264	    const dashboard = this.state.dashboard && (
265	      <Dashboard
266	        dashboard={this.state.dashboard}
267	        customMetric={true}
268	        template={this.props.template}
269	        labelValues={MetricsHelper.convertAsPromLabels(this.state.labelsSettings)}
270	        maximizedChart={expandedChart}
271	        expandHandler={this.expandHandler}
272	        onClick={this.onClickDataPoint}
273	        showSpans={this.state.showSpans}
274	        dashboardHeight={dashboardHeight}
275	        overlay={this.state.spanOverlay}
276	        timeWindow={evalTimeRange(this.props.timeRange)}
277	        brushHandlers={{ onDomainChangeEnd: (_, props) => this.onDomainChange(props.currentDomain.x) }}
278	      />
279	    );
280	
281	    const content = (
282	      <>
283	        {this.renderOptionsBar()}
284	        {this.state.dashboard !== undefined ? dashboard : this.renderFetchMetrics('Loading metrics')}
285	      </>
286	    );
287	
288	    return (
289	      <>
290	        {this.props.embedded ? (
291	          <>{content}</>
292	        ) : (
293	          <RenderComponentScroll onResize={height => this.setState({ tabHeight: height })}>
294	            <Card className={fullHeightStyle}>
295	              <CardBody>{content}</CardBody>
296	            </Card>
297	          </RenderComponentScroll>
298	        )}
299	
300	        <TimeDurationModal
301	          customDuration={true}
302	          isOpen={this.state.isTimeOptionsOpen}
303	          onConfirm={this.toggleTimeOptionsVisibility}
304	          onCancel={this.toggleTimeOptionsVisibility}
305	        />
306	      </>
307	    );
308	  }
309	
310	  private onTraceSpansChange = (checked: boolean, limit: number): void => {
311	    const urlParams = new URLSearchParams(location.getSearch());
312	    urlParams.set(URLParam.SHOW_SPANS, String(checked));
313	    if (checked) {
314	      urlParams.set(URLParam.TRACING_LIMIT_TRACES, String(limit));
315	    } else {
316	      urlParams.delete(URLParam.SHOW_SPANS);
317	    }
318	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
319	    this.setState({ showSpans: checked, traceLimit: limit });
320	  };
321	
322	  private renderOptionsBar = (): React.ReactNode => {
323	    const hasHistograms =
324	      this.state.dashboard !== undefined && this.state.dashboard.charts.some(chart => chart.metrics.some(m => m.stat));
325	
326	    const hasLabels = this.state.labelsSettings.size > 0;
327	
328	    return (
329	      <div ref={this.toolbarRef}>
330	        <Toolbar style={{ paddingBottom: 15 }}>
331	          <ToolbarGroup>
332	            {(hasHistograms || hasLabels) && (
333	              <ToolbarItem>
334	                <MetricsSettingsDropdown
335	                  onChanged={this.onMetricsSettingsChanged}
336	                  onLabelsFiltersChanged={this.onLabelsFiltersChanged}
337	                  direction={this.state.dashboard?.title || 'dashboard'}
338	                  labelsSettings={this.state.labelsSettings}
339	                  hasHistograms={hasHistograms}
340	                  hasHistogramsAverage={hasHistograms}
341	                  hasHistogramsPercentiles={hasHistograms}
342	                />
343	              </ToolbarItem>
344	            )}
345	
346	            <ToolbarItem>
347	              <MetricsRawAggregation onChanged={this.onRawAggregationChanged} />
348	            </ToolbarItem>
349	
350	            {this.props.tracingIntegration && (
351	              <ToolbarItem style={{ alignSelf: 'center' }}>
352	                <TraceSpansLimit
353	                  label="Spans"
354	                  onChange={this.onTraceSpansChange}
355	                  showSpans={this.state.showSpans}
356	                  traceLimit={this.state.traceLimit}
357	                />
358	              </ToolbarItem>
359	            )}
360	
361	            <KioskElement>
362	              <ToolbarItem style={{ marginLeft: 'auto' }}>
363	                <TimeDurationIndicator onClick={this.toggleTimeOptionsVisibility} />
364	              </ToolbarItem>
365	            </KioskElement>
366	          </ToolbarGroup>
367	
368	          <ToolbarGroup style={{ marginLeft: 'auto', paddingRight: '20px' }}>
369	            <GrafanaLinks
370	              links={this.state.grafanaInfo.externalLinks}
371	              namespace={this.props.namespace}
372	              object={this.props.workload ? this.props.workload : this.props.app}
373	              objectType={this.props.workload ? MetricsObjectTypes.WORKLOAD : MetricsObjectTypes.APP}
374	              datasourceUID={this.state.grafanaInfo.datasourceUID}
375	              version={this.props.version}
376	            />
377	          </ToolbarGroup>
378	        </Toolbar>
379	      </div>
380	    );
381	  };
382	
383	  private expandHandler = (expandedChart?: string): void => {
384	    const urlParams = new URLSearchParams(location.getSearch());
385	    urlParams.delete('expand');
386	
387	    if (expandedChart) {
388	      urlParams.set('expand', expandedChart);
389	    }
390	
391	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
392	  };
393	
394	  private toggleTimeOptionsVisibility = (): void => {
395	    this.setState(prevState => ({ isTimeOptionsOpen: !prevState.isTimeOptionsOpen }));
396	  };
397	}
398	
399	const mapStateToProps = (state: KialiAppState): ReduxStateProps => {
400	  return {
401	    kiosk: state.globalState.kiosk,
402	    timeRange: timeRangeSelector(state),
403	    tracingIntegration: state.tracingState.info ? state.tracingState.info.integration : false
404	  };
405	};
406	
407	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
408	  return {
409	    setTimeRange: bindActionCreators(UserSettingsActions.setTimeRange, dispatch)
410	  };
411	};
412	
413	export const CustomMetrics = connect(mapStateToProps, mapDispatchToProps)(CustomMetricsComponent);
